  1→import { useCallback, useEffect, useMemo, useState } from 'react';
  2→import { ActionPanel } from './components/action_panel/action_panel';
  3→import { Alert } from './components/alert/alert';
  4→import { ClipboardHistoryView } from './components/clipboard_history/clipboard_history_view';
  5→import { CommandPalette } from './components/command_palette/command_palette';
  6→import { Detail } from './components/detail/detail';
  7→import { DetailMetadata } from './components/detail/detail_metadata';
  8→import { EmojiPickerView } from './components/emoji_picker/emoji_picker_view';
  9→import { EmptyState } from './components/empty_state/empty_state';
 10→import { FileSearchView } from './components/file_search/file_search_view';
 11→import { Grid, GridItem } from './components/grid';
 12→import { HUDContainer } from './components/hud/hud_container';
 13→import { CalculatorIcon } from './components/icons';
 14→import { Kbd } from './components/kbd/kbd';
 15→import { List, ListItem, ListSection } from './components/list';
 16→import { QuickLook } from './components/quick_look/quick_look';
 17→import { SearchBar } from './components/search_bar/search_bar';
 18→import type { SearchDropdownSection } from './components/search_bar/search_dropdown';
 19→import { SearchDropdown } from './components/search_bar/search_dropdown';
 20→import { SettingsView } from './components/settings/settings_view';
 21→import { SnippetManagerView } from './components/snippet_manager/snippet_manager_view';
 22→import { ToastContainer } from './components/toast/toast_container';
 23→import { MOCK_COLORS, MOCK_SECTIONS } from './data/mock_data';
 24→import { useAlert } from './hooks/use_alert';
 25→import { useHUD } from './hooks/use_hud';
 26→import { useKeyboardShortcut } from './hooks/use_keyboard_shortcut';
 27→import {
 28→  NavigationContextProvider,
 29→  useNavigationStack,
 30→} from './hooks/use_navigation';
 31→import { useToast } from './hooks/use_toast';
 32→import type {
 33→  ColorItemData,
 34→  ListItemData,
 35→  ListItemMetadataEntry,
 36→  SectionData,
 37→} from './types';
 38→import { evaluate } from './utils/calculator';
 39→
 40→type NavViewData =
 41→  | { type: 'grid' }
 42→  | { type: 'clipboard' }
 43→  | { type: 'snippets' }
 44→  | { type: 'emoji' }
 45→  | { type: 'file-search' }
 46→  | { type: 'settings' }
 47→  | {
 48→      type: 'detail';
 49→      item: ListItemData;
 50→    };
 51→
 52→function filterSections(sections: SectionData[], query: string): SectionData[] {
 53→  if (!query) return sections;
 54→  const lower = query.toLowerCase();
 55→  return sections
 56→    .map(section => ({
 57→      ...section,
 58→      items: section.items.filter(
 59→        item =>
 60→          item.title.toLowerCase().includes(lower) ||
 61→          item.subtitle?.toLowerCase().includes(lower),
 62→      ),
 63→    }))
 64→    .filter(section => section.items.length > 0);
 65→}
 66→
 67→function filterColors(colors: ColorItemData[], query: string): ColorItemData[] {
 68→  if (!query) return colors;
 69→  const lower = query.toLowerCase();
 70→  return colors.filter(
 71→    c =>
 72→      c.title.toLowerCase().includes(lower) ||
 73→      c.subtitle?.toLowerCase().includes(lower),
 74→  );
 75→}
 76→
 77→function flattenItems(sections: SectionData[]): ListItemData[] {
 78→  return sections.flatMap(s => s.items);
 79→}
 80→
 81→function renderMetadataEntry(entry: ListItemMetadataEntry, index: number) {
 82→  switch (entry.type) {
 83→    case 'label':
 84→      return (
 85→        <DetailMetadata.Label
 86→          key={index}
 87→          title={entry.title}
 88→          text={entry.text}
 89→        />
 90→      );
 91→    case 'link':
 92→      return (
 93→        <DetailMetadata.Link
 94→          key={index}
 95→          title={entry.title}
 96→          text={entry.text}
 97→          target={entry.target}
 98→        />
 99→      );
100→    case 'tag-list':
101→      return (
102→        <DetailMetadata.TagList key={index} title={entry.title}>
103→          {entry.tags.map(tag => (
104→            <DetailMetadata.Tag
105→              key={tag.text}
106→              text={tag.text}
107→              color={tag.color}
108→            />
109→          ))}
110→        </DetailMetadata.TagList>
111→      );
112→    case 'separator':
113→      return <DetailMetadata.Separator key={index} />;
114→  }
115→}
116→
117→function ColorSwatch({ color }: { color: string }) {
118→  return (
119→    <div
120→      className="grid-item__color-swatch"
121→      style={{ backgroundColor: color }}
122→    />
123→  );
