185→interface ColorPickerViewProps {
186→  colors: ColorItemData[];
187→  onActiveIndexChange: (index: number) => void;
188→  onAction: (index: number) => void;
189→}
190→
191→function ColorPickerView({
192→  colors,
193→  onActiveIndexChange,
194→  onAction,
195→}: ColorPickerViewProps) {
196→  if (colors.length === 0) {
197→    return (
198→      <EmptyState
199→        icon={<SearchIcon />}
200→        title="No Colors"
201→        description="Try a different search term"
202→      />
203→    );
204→  }
205→
206→  return (
207→    <Grid
208→      itemCount={colors.length}
209→      columns={4}
210→      onActiveIndexChange={onActiveIndexChange}
211→      onAction={onAction}
212→    >
213→      {colors.map((color, index) => (
214→        <GridItem
215→          key={color.id}
216→          index={index}
217→          icon={<ColorSwatch color={color.color} />}
218→          title={color.title}
219→          subtitle={color.subtitle}
220→        />
221→      ))}
222→    </Grid>
223→  );
224→}
225→
226→function DetailView({ item }: { item: ListItemData }) {
227→  const itemDetail = item.detail;
228→  if (!itemDetail) return null;
229→  return (
230→    <Detail
231→      markdown={itemDetail.markdown}
232→      metadata={
233→        itemDetail.metadata ? (
234→          <DetailMetadata>
235→            {itemDetail.metadata.map(renderMetadataEntry)}
236→          </DetailMetadata>
237→        ) : undefined
238→      }
239→    />
