243→export function App() {
244→  const [query, setQuery] = useState('');
245→  const [filterValue, setFilterValue] = useState('all');
246→  const [colorFilterValue, setColorFilterValue] = useState('all');
247→  const [selectedIndex, setSelectedIndex] = useState(0);
248→  const [actionsOpen, setActionsOpen] = useState(false);
249→  const [quickLookOpen, setQuickLookOpen] = useState(false);
250→  const { toasts, show: showToast, hide: hideToast } = useToast();
251→  const { items: hudItems, show: showHUD } = useHUD();
252→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
253→  const nav = useNavigationStack<NavViewData>('Raycast');
254→  const { push } = nav;
255→
256→  const viewType = nav.currentEntry?.data.type ?? 'root';
257→
258→  const searchFilterSections: SearchDropdownSection[] = useMemo(
259→    () => [
260→      {
261→        options: [
262→          {
263→            label: 'All',
264→            value: 'all',
265→          },
266→        ],
267→      },
268→      {
269→        title: 'Types',
270→        options: [
271→          {
272→            label: 'Commands',
273→            value: 'commands',
274→          },
275→          {
276→            label: 'Applications',
277→            value: 'applications',
278→          },
279→        ],
280→      },
281→    ],
282→    [],
283→  );
284→
285→  const colorFilterSections: SearchDropdownSection[] = useMemo(
286→    () => [
287→      {
288→        options: [
289→          {
290→            label: 'All Colors',
291→            value: 'all',
292→          },
293→        ],
294→      },
295→      {
296→        title: 'Category',
297→        options: [
298→          {
299→            label: 'Warm',
300→            value: 'warm',
301→          },
302→          {
303→            label: 'Cool',
304→            value: 'cool',
305→          },
306→          {
307→            label: 'Neutral',
308→            value: 'neutral',
309→          },
310→        ],
311→      },
312→    ],
313→    [],
314→  );
315→
316→  useEffect(() => {
317→    if (nav.stackDepth === 0) {
318→      setQuery('');
319→      setFilterValue('all');
320→      setColorFilterValue('all');
321→      setSelectedIndex(0);
322→      setActionsOpen(false);
323→      setQuickLookOpen(false);
324→    }
325→  }, [nav.stackDepth]);
326→
327→  const filtered = useMemo(() => {
328→    let sections = MOCK_SECTIONS;
329→    if (filterValue === 'commands') {
330→      sections = sections.filter(
331→        s => s.title === 'Suggestions' || s.title === 'Commands',
332→      );
333→    } else if (filterValue === 'applications') {
334→      sections = sections.filter(s => s.title === 'Applications');
335→    }
336→    return filterSections(sections, query);
337→  }, [
338→    query,
339→    filterValue,
340→  ]);
341→  const calculatorResult = useMemo(() => {
342→    if (viewType !== 'root' || !query.trim()) return null;
343→    return evaluate(query);
344→  }, [
345→    query,
346→    viewType,
347→  ]);
348→
349→  const allItems = useMemo(() => {
350→    const items = flattenItems(filtered);
351→    if (calculatorResult) {
352→      const calcItem: ListItemData = {
353→        id: '__calculator__',
354→        title: `= ${calculatorResult}`,
355→        subtitle: query.trim(),
356→        icon: <CalculatorIcon />,
357→      };
358→      return [
359→        calcItem,
360→        ...items,
361→      ];
362→    }
363→    return items;
364→  }, [
365→    filtered,
366→    calculatorResult,
367→    query,
368→  ]);
369→  const filteredColors = useMemo(() => {
370→    let colors = MOCK_COLORS;
371→    if (colorFilterValue !== 'all') {
372→      colors = colors.filter(c => c.category === colorFilterValue);
373→    }
374→    return filterColors(colors, query);
375→  }, [
376→    query,
377→    colorFilterValue,
378→  ]);
379→
380→  const selectedItem =
381→    viewType === 'root' ? allItems[selectedIndex] : undefined;
382→
383→  const handleQueryChange = useCallback((value: string) => {
384→    setQuery(value);
385→    setSelectedIndex(0);
386→    setActionsOpen(false);
387→  }, []);
388→
389→  const handleFilterChange = useCallback((value: string) => {
390→    setFilterValue(value);
391→    setSelectedIndex(0);
392→  }, []);
393→
