449→    } else if (item.id === 'snippets') {
450→      push('Snippets', { type: 'snippets' });
451→      setQuery('');
452→      setSelectedIndex(0);
453→    } else if (item.id === 'emoji') {
454→      push('Search Emoji', { type: 'emoji' });
455→      setQuery('');
456→      setSelectedIndex(0);
457→    } else if (item.id === 'settings') {
458→      push('Settings', { type: 'settings' });
459→      setQuery('');
460→      setSelectedIndex(0);
