@use '../../styles/tokens' as *;

.action-panel {
  position: relative;
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: $action-panel-height;
  padding: 0 $space-2;
  border-top: 1px solid $border-100;
  background-color: $color-surface-footer;
  border-radius: 0 0 $radius-window $radius-window;
  flex-shrink: 0;
  animation: action-panel-slide-up $transition-slow ease-out both;
  animation-delay: $transition-fast;

