    background: none;
    border: none;
    padding: 0;
    cursor: pointer;
    font-family: $font-family;
    line-height: 1;
    &:focus-visible {
      outline: 2px solid $color-accent;
      outline-offset: 2px;
      border-radius: $radius-sm;
