  &__separator {
    width: 2px;
    height: 12px;
    background-color: $border-100;
    flex-shrink: 0;
  }

  &__actions-trigger {
    display: flex;
    align-items: center;
    gap: $space-2;
    background: none;
    border: none;
    padding: 0;
    cursor: pointer;
    font-family: $font-family;
    line-height: 1;
    transition: color $transition-fast ease;

    &:hover {
      .action-panel__actions-label {
        color: $color-text-primary;
