file.content:
@use '../../styles/tokens' as *;

.settings-view {
  display: flex;
  flex-direction: column;
  flex: 1;
  overflow-y: auto;
}

.settings-section {
  padding: $space-3 $space-4 $space-1;

  &__title {
    font-size: $font-xs;
    font-weight: $font-weight-medium;
    color: $text-600;
    letter-spacing: $letter-spacing-section;
    margin-bottom: $space-2;
  }
}

.settings-extension {
  display: flex;
  align-items: center;
  gap: $space-3;
  padding: $space-2 $space-3;
  border-radius: $radius-list-item;
  cursor: pointer;
  transition: background-color $transition-fast ease;

  &:hover {
    background: $color-surface-hover;
  }

  &__icon {
    flex-shrink: 0;
    width: $settings-ext-icon-size;
    height: $settings-ext-icon-size;
    display: flex;
    align-items: center;
    justify-content: center;

    svg {
      width: $settings-ext-icon-size;
      height: $settings-ext-icon-size;
    }
  }

  &__info {
    flex: 1;
    min-width: 0;
  }

  &__name {
    font-size: $font-base;
    color: $color-text-primary;
    font-weight: $font-weight-medium;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
  }

  &__meta {
    font-size: $font-xs;
    color: $text-400;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
  }

  &__toggle {
    flex-shrink: 0;
  }
}

.settings-toggle {
  position: relative;
  display: inline-flex;
  align-items: center;
  cursor: pointer;
}

.settings-toggle__input {
  position: absolute;
  opacity: 0;
  width: 0;
  height: 0;
  pointer-events: none;

  &:focus-visible + .settings-toggle__track {
    outline: 2px solid $color-accent;
    outline-offset: $space-half;
  }
}

.settings-toggle__track {
  width: $toggle-width;
  height: $toggle-height;
  border-radius: $radius-pill;
  background: $text-100;
  transition: background-color $transition-normal ease;
  pointer-events: none;

  .settings-toggle__input:checked + & {
    background: $color-accent;
  }
}

.settings-toggle__knob {
  position: absolute;
  top: $toggle-padding;
  left: $toggle-padding;
  width: $toggle-knob-size;
  height: $toggle-knob-size;
  border-radius: $radius-pill;
  background: $color-toggle-knob;
  transition: transform $transition-normal ease;
  pointer-events: none;

  .settings-toggle__input:checked ~ & {
    transform: translateX(
      #{$toggle-width - $toggle-knob-size - $toggle-padding * 2}
    );
  }
}

.settings-hotkey {
  display: flex;
  align-items: center;
  gap: $space-1;
  padding: $space-2 0;

  &__label {
    font-size: $font-sm;
    color: $text-600;
    font-weight: $font-weight-semibold;
    flex: 1;
  }
}

.settings-action-row {
  display: flex;
  align-items: center;
  gap: $space-3;
  padding: $space-2 $space-3;
  border-radius: $radius-list-item;
  cursor: pointer;
  transition: background-color $transition-fast ease;

  &:hover {
    background: $color-surface-hover;
  }

  &__icon {
    flex-shrink: 0;
    width: $space-5;
    height: $space-5;
    color: $text-600;
    display: flex;
    align-items: center;
    justify-content: center;
  }

  &__label {
    font-size: $font-base;
    color: $color-text-primary;
    flex: 1;
  }

  &__hint {
    font-size: $font-xs;
    color: $text-400;
  }

  &--destructive &__label {
    color: $color-destructive;
  }

  &--destructive &__icon {
    color: $color-destructive;
  }
}

input.content:
@use '../../styles/tokens' as *;

.command-palette-overlay {
  position: fixed;
  inset: 0;
  display: flex;
  align-items: flex-start;
  justify-content: center;
  padding-top: 15vh;
}

.command-palette {
  position: relative;
  width: $command-palette-width;
  max-width: calc(100vw - $space-6 * 2);
  max-height: 500px;
  display: flex;
  flex-direction: column;
  background: linear-gradient(
    180deg,
    var(--color-bg-40) 0%,
    var(--color-surface-40) 100%
  );
  backdrop-filter: blur(72px) saturate(200%);
  -webkit-backdrop-filter: blur(72px) saturate(200%);
  border-radius: $radius-window;
  border: none;
  box-shadow:
    var(--shadow-window),
    inset 0 0 0 1px var(--border-200);
  overflow: hidden;
  animation: palette-appear $transition-slow ease-out both;
}

.command-palette__body {
  display: flex;
  flex: 1;
  min-height: 0;
  overflow: hidden;
  position: relative;
}

.command-palette__nav-view {
  display: flex;
  flex: 1;
  min-height: 0;
  overflow: hidden;
  width: 100%;

  &--push {
    animation: nav-slide-in-left $transition-slow ease-out both;
  }

  &--pop {
    animation: nav-slide-in-right $transition-slow ease-out both;
  }
}

@keyframes nav-slide-in-left {
  from {
    opacity: 0;
    transform: translateX(40px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

@keyframes nav-slide-in-right {
  from {
    opacity: 0;
    transform: translateX(-40px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

.command-palette__list-container {
  display: flex;
  flex-direction: column;
  flex: 1;
  min-width: 0;
  overflow: hidden;

  .command-palette__body--has-detail & {
    flex: 0 0 40%;
  }
}

@use '../../styles/tokens' as *;

.search-bar {
  display: flex;
  align-items: center;
  height: $search-bar-height;
  padding: 0 $space-4;
  border-bottom: 1px solid var(--border-100);
  gap: $space-3;
}

.search-bar__icon {
  flex-shrink: 0;
  color: var(--text-400);
}

.search-bar__breadcrumbs {
  display: flex;
  align-items: center;
  flex-shrink: 0;
  gap: $space-half;
}

.search-bar__breadcrumb {
  display: inline-flex;
  align-items: center;
  padding: $space-half $space-2;
  border: none;
  border-radius: $radius-sm;
  background: var(--color-surface-hover);
  font-family: $font-family;
  font-size: $font-sm;
  color: var(--text-600);
  cursor: pointer;
  white-space: nowrap;
  transition: background-color $transition-fast ease;

  &:hover {
    background: var(--border-100);
  }

  &:focus-visible {
    outline: 2px solid var(--color-accent);
    outline-offset: -1px;
  }

  &--current {
    cursor: default;

    &:hover {
      background: var(--color-surface-hover);
    }
  }
}

.search-bar__breadcrumb-chevron {
  flex-shrink: 0;
  color: var(--text-400);
}

.search-bar__input {
  flex: 1;
  min-width: 0;
  height: 100%;
  border: none;
  outline: none;
  background: transparent;
  font-family: $font-family;
  font-size: $font-search;
  color: var(--color-text-primary);
  caret-color: var(--color-accent);

  &::placeholder {
    color: var(--text-400);
  }
}

@use '../../styles/tokens' as *;

.search-dropdown {
  position: relative;
  flex-shrink: 0;
}

.search-dropdown__trigger {
  display: flex;
  align-items: center;
  gap: $space-1;
  padding: $space-1 $space-2;
  border: none;
  border-radius: $radius-kbd;
  background: var(--text-100);
  font-family: $font-family;
  font-size: $font-sm;
  color: var(--text-600);
  cursor: pointer;
  white-space: nowrap;
  transition: background-color $transition-fast ease;
  line-height: 1;
  height: $search-dropdown-trigger-height;

  &:hover {
    background: var(--border-200);
  }

  &:focus-visible {
    outline: 2px solid var(--color-accent);
    outline-offset: -1px;
  }
}

.search-dropdown__trigger-label {
  max-width: 120px;
  overflow: hidden;
  text-overflow: ellipsis;
}

.search-dropdown__trigger-chevron {
  flex-shrink: 0;
  transition: transform $transition-fast ease;

  &--open {
    transform: rotate(180deg);
  }
}

.search-dropdown__menu {
  position: absolute;
  top: calc(100% + $space-2);
  right: 0;
  min-width: $search-dropdown-menu-min-width;
  max-height: $search-dropdown-menu-max-height;
  overflow: hidden;
  background-color: var(--color-surface);
  border: 1px solid var(--border-100);
  border-radius: $radius-lg;
  box-shadow: var(--shadow-popover);
  z-index: $z-search-dropdown;
  animation: search-dropdown-appear $transition-normal ease-out both;
}

.search-dropdown__menu-content {
  padding: $space-1;
  overflow-y: auto;
  max-height: calc($search-dropdown-menu-max-height - 2 * $space-1);
}

.search-dropdown__separator {
  height: 1px;
  margin: $space-1 $space-2;
  background-color: var(--border-100);
}

.search-dropdown__section-title {
  padding: $space-1 + $space-half $space-3;
  font-family: $font-family;
  font-size: $font-xs;
  font-weight: $font-weight-medium;
  color: var(--text-400);
  line-height: 1;
  white-space: nowrap;
  user-select: none;
}

.search-dropdown__option {
  display: flex;
  align-items: center;
  gap: $space-2;
  width: 100%;
  padding: $space-2 $space-3;
  background: none;
  border-radius: $radius-md;
  cursor: pointer;
  color: var(--color-text-primary);
  font-family: $font-family;
  font-size: $font-sm;
  line-height: 1;
  text-align: left;
  transition: background-color $transition-fast ease;

  &:hover,
  &--active {
    background-color: var(--color-accent);
    color: var(--color-text-on-accent);

    .search-dropdown__check {
      color: var(--color-text-on-accent);
    }
  }

  &:focus-visible {
    outline: 2px solid var(--color-accent);
    outline-offset: -2px;
    border-radius: $radius-md;
  }
}

.search-dropdown__option-icon {
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  width: 16px;
  height: 16px;
}

.search-dropdown__option-label {
  flex: 1;
  white-space: nowrap;
}

.search-dropdown__check {
  flex-shrink: 0;
  color: var(--color-accent);
}

@keyframes search-dropdown-appear {
  from {
    opacity: 0;
    transform: scale(0.96) translateY(-4px);
  }

  to {
    opacity: 1;
    transform: scale(1) translateY(0);
  }
}

@use '../../../styles/tokens' as *;

.list-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: $list-item-height;
  padding: 0 $space-2;
  border-radius: $radius-list-item;
  cursor: pointer;
  transition: background-color $transition-fast ease;

  &:hover:not(&--active) {
    background-color: var(--color-surface-hover);
  }

  &:focus-visible {
    outline: 2px solid var(--color-accent);
    outline-offset: -2px;
  }

  &--active {
    background-color: var(--color-selection-background);
  }
}

.list-item__left {
  display: flex;
  align-items: center;
  gap: $space-3;
  min-width: 0;
  flex: 1;
}

.list-item__icon {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 20px;
  height: 20px;
  flex-shrink: 0;
  color: var(--text-600);
}

.list-item__title {
  font-size: $font-base;
  color: var(--color-text-primary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  min-width: 0;
}

.list-item__subtitle {
  font-size: $font-sm;
  color: var(--text-600);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  flex-shrink: 1;
  min-width: 0;
}

.list-item__accessories {
  display: flex;
  align-items: center;
  gap: $space-2;
  flex-shrink: 0;
  margin-left: $space-2;
}

.list-item__accessory {
  display: inline-flex;
  align-items: center;
  gap: $space-1;
}

.list-item__accessory-text {
  font-size: $font-xs;
  color: var(--text-400);
  white-space: nowrap;
}

.list-item__accessory-tag {
  display: inline-flex;
  align-items: center;
  height: 22px;
  padding: 0 $space-2;
  border-radius: $radius-kbd;
  font-size: $font-sm;
  font-weight: $font-weight-medium;
  white-space: nowrap;
  color: var(--text-600);
  background-color: var(--text-100);
}

@use '../../../styles/tokens' as *;

.list-section {
  &:not(:first-child) {
    margin-top: $space-2;
  }
}

.list-section__header {
  font-size: $font-sm;
  font-weight: $font-weight-medium;
  color: var(--text-600);
  letter-spacing: $letter-spacing-section;
  padding: $space-1 $space-2;
  line-height: 1;
}

@use '../../styles/tokens' as *;

.action-panel {
  position: relative;
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: $action-panel-height;
  padding: 0 $space-2;
  border-top: 1px solid var(--border-100);
  background-color: var(--color-surface-footer);
  border-radius: 0 0 $radius-window $radius-window;
  flex-shrink: 0;
  animation: action-panel-slide-up $transition-slow ease-out both;
  animation-delay: $transition-fast;

  &__left {
    display: flex;
    align-items: center;
    gap: $space-2;
  }

  &__logo {
    flex-shrink: 0;
  }

  &__context {
    font-family: $font-family;
    font-size: $font-sm;
    color: var(--text-600);
    white-space: nowrap;
    line-height: 1;
  }

  &__right {
    display: flex;
    align-items: center;
    gap: $space-2;
  }

  &__primary-action {
    display: flex;
    align-items: center;
    gap: $space-2;
    background: none;
    border: none;
    padding: 0;
    cursor: pointer;
    font-family: $font-family;
    line-height: 1;
    &:focus-visible {
      outline: 2px solid var(--color-accent);
      outline-offset: 2px;
      border-radius: $radius-sm;
    }
  }

  &__primary-label {
    font-size: $font-xs;
    font-weight: $font-weight-semibold;
    color: var(--color-text-primary);
    white-space: nowrap;
  }

  &__separator {
    width: 2px;
    height: 12px;
    background-color: var(--border-100);
    flex-shrink: 0;
  }

  &__actions-trigger {
    display: flex;
    align-items: center;
    gap: $space-2;
    background: none;
    border: none;
    padding: 0;
    cursor: pointer;
    font-family: $font-family;
    line-height: 1;
    transition: color $transition-fast ease;

    &:hover {
      .action-panel__actions-label {
        color: var(--color-text-primary);
      }
    }

    &:focus-visible {
      outline: 2px solid var(--color-accent);
      outline-offset: 2px;
      border-radius: $radius-sm;
    }
  }

  &__actions-label {
    font-size: $font-xs;
    color: var(--text-600);
    white-space: nowrap;
  }

  &__shortcut {
    display: inline-flex;
    align-items: center;
    gap: $space-half;
  }
}

