@use '../../styles/tokens' as *;

.form {
  display: flex;
  flex-direction: column;
  flex: 1;
  overflow-y: auto;
  padding: $space-3;
}

.form__fields {
  display: flex;
  flex-direction: column;
  gap: $space-4;
}

.form-field {
  display: flex;
  flex-direction: column;
  gap: $space-1;
}

.form-field__header {
  display: flex;
  align-items: baseline;
  justify-content: space-between;
  gap: $space-2;
}

.form-field__label {
  font-size: $font-sm;
  color: var(--text-600);
  font-weight: $font-weight-semibold;
}

.form-field__description {
  font-size: $font-xs;
  color: var(--text-400);
}

.form-field__error {
  font-size: $font-xs;
  color: var(--color-destructive);
}

.form-input {
  width: 100%;
  padding: $space-2 $space-3;
  background: var(--color-background);
  border: 1px solid var(--border-100);
  border-radius: $radius-md;
  color: var(--color-text-primary);
  font-family: $font-family;
  font-size: $font-md;
  outline: none;
  transition: border-color $transition-fast ease;

  &::placeholder {
    color: var(--text-400);
  }

  &:focus {
    border-color: var(--color-accent);
  }

  .form-field--error & {
    border-color: var(--color-destructive);
  }
}

.form-password-wrapper {
  position: relative;
  display: flex;
  align-items: center;
}

.form-input--password {
  padding-right: $space-8;
}

.form-password-toggle {
  position: absolute;
  right: $space-2;
  display: flex;
  align-items: center;
  justify-content: center;
  width: $space-6;
  height: $space-6;
  padding: 0;
  border: none;
  border-radius: $radius-sm;
  background: transparent;
  color: var(--text-400);
  cursor: pointer;
  transition: color $transition-fast ease;

  &:hover {
    color: var(--color-text-primary);
  }

  &:focus-visible {
    outline: 2px solid var(--color-accent);
    outline-offset: 2px;
  }
}

.form-separator {
  width: 100%;
  height: 0;
  margin: 0;
  padding: 0;
  border: none;
  border-top: 1px solid var(--border-100);
}

.form-input--textarea {
  resize: vertical;
  min-height: 80px;
  line-height: 1.5;
}

.form-input--select {
  appearance: none;
  cursor: pointer;
  background-image: url("data:image/svg+xml,%3Csvg width='10' height='6' viewBox='0 0 10 6' fill='none' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M1 1L5 5L9 1' stroke='%2398989d' stroke-width='1.5' stroke-linecap='round' stroke-linejoin='round'/%3E%3C/svg%3E");
  background-repeat: no-repeat;
  background-position: right $space-3 center;
  padding-right: $space-7;

  option {
    background: var(--color-surface);
    color: var(--color-text-primary);
  }
}

.form-input--date {
  cursor: pointer;
  color-scheme: dark;

  &::-webkit-calendar-picker-indicator {
    filter: invert(0.6);
    cursor: pointer;
  }
}

.form-checkbox {
  display: flex;
  flex-direction: column;
  gap: $space-1;
}

.form-checkbox__row {
  display: flex;
  align-items: center;
  gap: $space-2;
}

$checkbox-size: 16px;

.form-checkbox__input {
  position: absolute;
  opacity: 0;
  width: 0;
  height: 0;
  pointer-events: none;

  &:focus-visible + .form-checkbox__box {
    outline: 2px solid var(--color-accent);
    outline-offset: 2px;
  }
}

.form-checkbox__box {
  display: flex;
  align-items: center;
  justify-content: center;
  width: $checkbox-size;
  height: $checkbox-size;
  border: 1px solid var(--border-100);
  border-radius: $radius-sm;
  background: var(--color-background);
  color: var(--color-text-on-accent);
  pointer-events: none;
  flex-shrink: 0;
  transition:
    background-color $transition-fast ease,
    border-color $transition-fast ease;

  .form-checkbox--error & {
    border-color: var(--color-destructive);
  }

  &--checked {
    background: var(--color-accent);
    border-color: var(--color-accent);
  }
}

.form-checkbox__label {
  font-size: $font-md;
  color: var(--color-text-primary);
  cursor: pointer;
}

.form-checkbox__error {
  font-size: $font-xs;
  color: var(--color-destructive);
  padding-left: calc($checkbox-size + $space-2);
}

.form-checkbox__description {
  font-size: $font-xs;
  color: var(--text-400);
  padding-left: calc($checkbox-size + $space-2);
}

